from pathlib import Path
base=Path('.gsd/milestones/M001/slices')
for sid in [f'S{i:02d}' for i in range(1,11)]:
    p=base/sid/f'{sid}-SUMMARY.md'
    print(f'## {sid} {p.exists()}')
    if not p.exists():
        continue
    text=p.read_text(encoding='utf-8')
    # Extract one-liner/bold line, key files, evidence table commands, section snippets.
    lines=text.splitlines()
    # title and bold one-liners
    for line in lines[:80]:
        if line.startswith('# ') or (line.startswith('**') and line.endswith('**')):
            print(line[:240])
    # key files frontmatter if present
    in_key=False
    key=[]
    for line in lines[:80]:
        if line.strip()=='key_files:':
            in_key=True; continue
        if in_key:
            if line.startswith('  - '): key.append(line[4:])
            elif line and not line.startswith(' '): in_key=False
    if key: print('key_files:', ', '.join(key[:8]))
    # verification table commands
    cmds=[]
    for line in lines:
        if line.startswith('|') and not line.startswith('|---') and 'Command' not in line:
            cells=[c.strip() for c in line.strip('|').split('|')]
            if len(cells)>=5 and cells[2].lstrip('-').isdigit():
                cmds.append(cells[1])
    if cmds:
        print('commands:', '; '.join(cmds[:6]))
    # scan for requirement-ish terms summary snippets
    for marker in ['## What Happened','## Verification','## Diagnostics','## Files Created/Modified']:
        try:
            i=lines.index(marker)
        except ValueError:
            continue
        snippet=' '.join(l.strip() for l in lines[i+1:i+5] if l.strip())
        print(marker+':', snippet[:500])
    print()

