    missing = sorted(expected - record_ids)
    extra = sorted(record_ids - expected)
    if missing:
        problems.append(f"missing requirement records: {', '.join(missing)}")
    if extra:
        problems.append(f"unexpected requirement records: {', '.join(extra)}")

