from pathlib import Path
import re

root = Path('.')
planning = (root / '.planning/REQUIREMENTS.md').read_text(encoding='utf-8')
research = (root / '.gsd/milestones/M001/slices/S11/S11-RESEARCH.md').read_text(encoding='utf-8')

planning_desc = {}
for line in planning.splitlines():
    m = re.match(r'- \[[ x]\] \*\*([A-Z]+-\d{2})\*\*: (.+)$', line)
    if m:
        planning_desc[m.group(1)] = m.group(2).strip()

def normalize_support(value):
    if value.lower() == 'none':
        return '-'
    ids = []
    for start, end in re.findall(r'S(\d{2})\s*-\s*S(\d{2})', value):
        for number in range(int(start), int(end) + 1):
            ids.append(f'S{number:02d}')
    scrubbed = re.sub(r'S\d{2}\s*-\s*S\d{2}', ' ', value)
    ids.extend(re.findall(r'S\d{2}', scrubbed))
    ordered = []
    for sid in ids:
        if sid not in ordered:
            ordered.append(sid)
    return ', '.join(ordered) if ordered else '-'

rows = []
in_table = False
for line in research.splitlines():
    if line.startswith('| R001 |'):
        in_table = True
    if not in_table:
        continue
    if not line.startswith('| R'):
        if rows:
            break
        continue
    cells = [c.strip() for c in line.strip('|').split('|')]
    if len(cells) != 6:
        raise SystemExit(f'bad matrix row: {line}')
    req_id, old_req, short_title, owner, supporting, proof = cells
    desc = planning_desc.get(old_req, short_title)
    if req_id == 'R009':
        short_title = 'Log level choices match the validated Settings contract, including schema-supported Warning.'
        desc = desc + ' S02 intentionally validates Warning in addition to the Python tab visible Debug/Info/Error labels because the reference settings schema accepts persisted WARNING.'
    rows.append({'id': req_id, 'old_req': old_req, 'short_title': short_title.rstrip('.'), 'description': desc, 'owner': owner, 'supporting': normalize_support(supporting), 'proof': proof.rstrip('.')})

if len(rows) != 54:
    raise SystemExit(f'expected 54 rows, parsed {len(rows)}')

class_by_prefix = {'FOUND':'launchability','SET':'continuity','DISC':'integration','OVR':'core-capability','F4SE':'core-capability','SCAN':'core-capability','TOOL':'core-capability','ABOUT':'core-capability','SAFE':'quality-attribute'}
class_override = {'FOUND-03':'operability','FOUND-04':'operability','FOUND-05':'constraint','SET-06':'failure-visibility','F4SE-05':'quality-attribute','TOOL-05':'compliance/security','TOOL-06':'quality-attribute','ABOUT-04':'failure-visibility','SAFE-04':'compliance/security','SAFE-05':'constraint'}

lines = []
lines += ['# Requirements','', 'This file is the explicit capability and coverage contract for the project.', '', '## Remediation Note', '']
lines.append('S11 rebuilt this Markdown traceability matrix directly from .planning/REQUIREMENTS.md and completed M001 slice evidence because this execution tool session did not expose a DB-backed requirement update capability. The source of truth for v1 requirement titles is the list order: R001-R005 FOUND, R006-R011 SET, R012-R016 DISC, R017-R024 OVR, R025-R029 F4SE, R030-R039 SCAN, R040-R045 TOOL, R046-R049 ABOUT, and R050-R054 SAFE.')
lines.append('')
lines.append('All validated statuses below are evidence-backed by completed S01-S10 summaries, task summaries, source-contract/runtime tests, and recorded Cargo gates. This document does not claim manual desktop, live Fallout 4 install, live network, or destructive real-file UAT unless such evidence is separately recorded in a slice artifact.')
lines += ['', '## Active', '', 'No active v1 requirements remain after S01-S10 evidence reconciliation. Future validation should reopen or add a requirement instead of weakening proof text if new gaps are discovered.', '', '## Validated']
for row in rows:
    prefix = row['old_req'].split('-', 1)[0]
    cls = class_override.get(row['old_req'], class_by_prefix.get(prefix, 'core-capability'))
    row['class'] = cls
    lines += ['', f"### {row['id']} — {row['old_req']}: {row['short_title']}", f'- Class: {cls}', '- Status: validated', f"- Description: {row['description']}", '- Source: .planning/REQUIREMENTS.md v1 requirement list, reconciled by S11 against completed M001 evidence.', f"- Primary owning slice: {row['owner']}", f"- Supporting slices: {row['supporting']}", '- Evidence class: completed slice/task summaries, automated Rust tests, source-contract/runtime wiring checks, and recorded Cargo gates; no unrecorded manual UAT is claimed.', f"- Validation: {row['proof']}."]
    if row['id'] == 'R009':
        lines.append('- Notes: S02 discrepancy note preserved: the Rust port intentionally validates Warning in addition to the Python tab visible Debug/Info/Error labels because the reference settings schema accepts persisted WARNING.')
lines += ['', '## Deferred', '', 'No v1 requirements are deferred in M001 after S01-S10 completion evidence was reconciled. v2 enhancements remain documented in .planning/REQUIREMENTS.md.', '', '## Out of Scope', '', 'No v1 requirements were moved out of scope during S11. The original out-of-scope product boundaries remain documented in .planning/REQUIREMENTS.md.', '', '## Traceability', '', '| ID | Requirement | Class | Status | Primary owner | Supporting | Proof |', '|---|---|---|---|---|---|---|']
for row in rows:
    lines.append(f"| {row['id']} | {row['old_req']} | {row['class']} | validated | {row['owner']} | {row['supporting']} | {row['proof']}. |")
lines += ['', '## Coverage Summary', '', '- Total v1 requirements: 54', '- Active requirements: 0', '- Validated requirements: 54', '- Deferred requirements: 0', '- Out-of-scope v1 requirements: 0', '- Requirements with primary owner: 54', '- Requirements with proof text: 54', '- Requirements without primary owner: 0', '- Requirements without proof text: 0', '', '---', '*Requirements traceability remediated by S11 T01 from completed M001 evidence.*']
(root / '.gsd/REQUIREMENTS.md').write_text('\n'.join(lines) + '\n', encoding='utf-8')
PY

